import React, { useState, useEffect } from 'react';
import { fetchPosts, randomPicsumUrl } from '../utils/picsum';
import './FourSteps.css';

const DEFAULT_STEPS = [
  { num: '1', title: 'Scan', desc: 'We use an AI-powered scanner to capture a detailed 3D image of your teeth.' },
  { num: '2', title: 'Plan', desc: 'Our orthodontists design your customised smile plan using advanced software.' },
  { num: '3', title: 'Fabricate', desc: 'We manufacture your custom aligners using 3D printing and laser precision.' },
  { num: '4', title: 'Wear', desc: 'Your Whistle Aligners and expert clinic team monitor your progress from start to finish.' },
];

export default function FourSteps() {
  const [steps, setSteps] = useState(DEFAULT_STEPS);
  const [stepsImage, setStepsImage] = useState(randomPicsumUrl(420, 500));

  useEffect(() => {
    let active = true;
    fetchPosts(4)
      .then((data) => {
        if (!active || !data?.posts?.length) return;
        setSteps(
          data.posts.slice(0, 4).map((post, index) => ({
            num: `${index + 1}`,
            title: post.title,
            desc: post.body.slice(0, 90),
          }))
        );
      })
      .catch(() => {
        // keep default steps if fetch fails
      })
      .finally(() => {
        if (active) setStepsImage(randomPicsumUrl(420, 500));
      });
    return () => { active = false; };
  }, []);

  return (
    <section className="steps-section">
      <div className="steps-inner">
        <div className="steps-card">
          <div className="steps-copy">
            <h2 className="steps-title">Get your perfect smile in<br />four simple steps</h2>
            <div className="steps-list">
              {steps.map((s, i) => (
                <div key={i} className="step-item">
                  <div className="step-num">{s.num}</div>
                  <div className="step-body">
                    <h3 className="step-title">{s.title}</h3>
                    <p className="step-desc">{s.desc}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="steps-media">
            <div className="steps-image">
              <img src={stepsImage} alt="Dentist scanning" className="steps-img image-hover-scale" />
              <button type="button" className="steps-play-btn" aria-label="Play video">
                ?
              </button>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
